# -*- coding: utf-8 -*-# ==============================================================# Departamento de Ingeniería Mecánica - Universidad de Chile# Trabajo de Memoria de Título:# "Implementación de algoritmos de reconocimiento de objetos#  para la identificación de fallas en correas transportadoras"# Autor: Fernando N.# --------------------------------------------------------------# Archivo: check_environment.py# Descripción: Script de validación de entorno para PyTorch.# Versión objetivo: ROCm 7.1.1 (Windows) + PyTorch 2.9.0 (Preview)# ==============================================================import torchimport sysimport platformimport subprocessdef print_section(title):    print("\n" + "=" * 60)    print(f" {title}")    print("=" * 60)def main():    print_section("1. DIAGNÓSTICO DEL SISTEMA")    print(f"Sistema Operativo : {platform.system()} {platform.release()}")    print(f"Arquitectura      : {platform.machine()}")    print(f"Versión de Python : {sys.version.split()[0]}")    print_section("2. VERIFICACIÓN DE PYTORCH")    print(f"Versión instalada : {torch.__version__}")    # Verificación de build específico    if "rocmsdk" not in torch.__version__:        print("⚠️  ADVERTENCIA: La versión instalada no parece corresponder al build de ROCm SDK.")    else:        print("✅ Build correcto detectado (rocmsdk).")    # Detección de Backend    cuda_ok = torch.cuda.is_available()    hip_version = getattr(torch.version, 'hip', 'No detectado')    print(f"Soporte CUDA/ROCm : {'DISPONIBLE' if cuda_ok else 'NO DISPONIBLE'}")    print(f"Versión HIP interna: {hip_version}")    if not cuda_ok:        print("\n❌ CRÍTICO: PyTorch no detecta la GPU. Verifique la instalación del SDK de ROCm 7.1.1.")        print("   Asegúrese de haber reiniciado la terminal después de la instalación.")        return    device_id = torch.cuda.current_device()    device_name = torch.cuda.get_device_name(device_id)    print(f"Dispositivo activo: {device_name} (ID: {device_id})")    print_section("3. PRUEBA DE TENSOR (TEST DE ESTRÉS SIMPLE)")    try:        device = torch.device('cuda')        # Creación de tensores        print("Allocando tensores en VRAM...", end=" ")        x = torch.randn(2048, 2048, device=device)        y = torch.randn(2048, 2048, device=device)        print("OK")        # Operación matemática (Matrix Multiplication)        print("Ejecutando multiplicación de matrices (GEMM)...", end=" ")        z = torch.matmul(x, y)        # Sincronización para medir éxito real (las ops de GPU son asíncronas)        torch.cuda.synchronize()        print("OK")        print(f"Resultado shape: {z.shape}")        print(f"Dispositivo de salida: {z.device}")        print("\n✅ PRUEBA DE CÓMPUTO COMPLETADA EXITOSAMENTE.")    except Exception as e:        print(f"\n❌ ERROR DURANTE EL CÓMPUTO: {e}")        import traceback        traceback.print_exc()    print_section("4. ENTORNO DETALLADO (torch.utils.collect_env)")    try:        # Capturamos la salida para evitar que inunde la consola si falla        subprocess.run([sys.executable, "-m", "torch.utils.collect_env"], check=True)    except Exception as e:        print(f"No se pudo recolectar el entorno detallado: {e}")if __name__ == "__main__":    main()